<nav aria-label="Application steps" class="step-indicator mb-4">
    <ol class="d-flex list-unstyled justify-content-between p-0 m-0">
        @for (int i = 0; i < StepLabels.Length; i++)
        {
            var step = i;
            var isCompleted = step < CurrentStep;
            var isCurrent = step == CurrentStep;
            var isFuture = step > CurrentStep;

            <li class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                role="button"
                @onclick="() => HandleStepClick(step)"
                @onclick:preventDefault>
                <div class="step-circle mx-auto mb-1 @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(step + 1)</span>
                    }
                </div>
                <small class="@(isFuture ? "text-muted" : isCurrent ? "fw-bold text-primary" : "text-success")">@StepLabels[step]</small>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepLabels = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private async Task HandleStepClick(int step)
    {
        if (step < CurrentStep)
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

