{"file_text": "<style>
    .step-circle {
        width: 36px;
        height: 36px;
        border-radius: 50%;
        display: flex;
        align-items: center;
        justify-content: center;
        font-weight: bold;
        font-size: 0.9rem;
        transition: all 0.2s;
    }

    .step-item {
        cursor: default;
        position: relative;
    }

    .step-item.completed {
        cursor: pointer;
    }

    .step-item.completed:hover .step-circle {
        opacity: 0.8;
    }

    .step-item:not(:last-child)::after {
        content: "";
        position: absolute;
        top: 18px;
        left: calc(50% + 22px);
        width: calc(100% - 44px);
        height: 2px;
        background-color: #dee2e6;
    }

    .step-item.completed:not(:last-child)::after {
        background-color: #198754;
    }
</style>
