{"file_text": "<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <label class="form-label">Write your cover letter</label>
    <textarea class="form-control" rows="10" maxlength="@MaxLength"
              @bind="CoverLetter" @bind:event="oninput"
              @bind:after="NotifyChanged"></textarea>
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / @MaxLength characters
    </div>
</div>

@if (!string.IsNullOrEmpty(ErrorMessage))
{
    <div class="alert alert-danger">@ErrorMessage</div>
}

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private async Task NotifyChanged()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            ErrorMessage = "A cover letter is required.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}
", "path": "/tmp/sv-6b7071fc68b44feabd7a5c41264cc73d/Components/Pages/Apply/CoverLetterStep.razor"}

{"file_text": "@using sv_6b7071fc68b44feabd7a5c41264cc73d.Models

<h4 class="mb-3">Review & Submit</h4>

@if (SubmittedId.HasValue)
{
    <div class="alert alert-success text-center">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@SubmittedId</strong>. We will be in touch soon.</p>
    </div>
}
else
{
    @* Personal Info Section *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    @* Work History Section *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-no-border">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") &mdash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    @* References Section *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) &mdash; @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    @* Cover Letter Section *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEdit.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
                <span>Submitting…</span>
            }
            else
            {
                <span>Submit Application</span>
            }
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public int? SubmittedId { get; set; }
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    private string? ErrorMessage;
    private bool isSubmitting;

    private async Task HandleSubmit()
    {
        ErrorMessage = null;
        isSubmitting = true;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}
